@import url("im_design_system/v0.1.0/css/common.css");
@import url('im_design_system/imds-iconfont/css/imds-iconfont.min.css');

/* initialization and common styles */
html {
  font-size: 14px;
  overflow-y: auto;
}

.imds-page-title {
  min-height: 3.572rem;
  padding: 0 1.14rem 0 0;
  border-bottom: 1px solid #d5d5d5;
}

.imds-page-title .subtitle {
  font-size: 0.86rem;
}

.imds-page-title .imds-back .button,
.imds-page-title .imds-refresh .button {
  width: 3.22rem;
  height: 3.22rem;
  font-size: 1.43rem;
}

/* show scrollbar when the search area is longer than the screen width */
.search-box {
  max-height: 100%;
  overflow-y: auto;
}

/* fixed display position of the button area */
.im-hichee-container.im-hichee-production-mode .search-button-area {
  position: sticky;
  bottom: 0;
}

/* Style start for overlay */
/* Overlay parent element */
.overlay-wrap-area {
  position: relative;
}

/* Search area overlay display */
.im-hichee-container.im-hichee-production-mode .search-area {
  position: absolute;
  top: 0;
  left: 0;
  z-index: 9999;
  margin-top: -1rem;
}
/* Style end for overlay */

/* override imported css */
.imds-table-operation-area .button,
.imds-page-title .search-button .button,
.search-box .button{
  min-width: 8em;
}

.table-header-edge-centering th:first-of-type, .table-header-edge-centering th:last-of-type{
  text-align: center;
}

.fa-angle-down {
  padding-left: 1em;
}

